61	/* ---- Static allocation limits ---- */
62	
63	#define MAX_LINE_LEN   512
64	#define MAX_TOKENS       32
65	#define MAX_TOKEN_LEN   128
66	#define MAX_VARS         64
67	#define MAX_VAR_NAME     32
68	#define MAX_VAR_VAL     128
69	#define MAX_NEST         64
70	#define MAX_FIELDS       16
71	
72	/* ---- String helpers ---- */
73	
74	int str_len(char *s) {
75	    int n = 0;
76	    while (s[n]) n = n + 1;
77	    return n;
78	}
79	
80	int str_eq(char *a, char *b) {
81	    int i = 0;
82	    while (a[i] && b[i]) {
83	        if (a[i] != b[i]) return 0;
84	        i = i + 1;
85	    }
86	    return a[i] == b[i];
87	}
88	
89	void str_copy(char *dst, char *src) {
90	    int i = 0;
91	    while (src[i]) {
92	        dst[i] = src[i];
93	        i = i + 1;
94	    }
95	    dst[i] = 0;
96	}
97	
98	int str_starts_with(char *s, char *prefix) {
99	    int i = 0;
100	    while (prefix[i]) {
101	        if (s[i] != prefix[i]) return 0;
102	        i = i + 1;
103	    }
104	    return 1;
105	}
106	
107	int str_to_int(char *s) {
108	    int n = 0;
109	    int neg = 0;
110	    int i = 0;
111	    if (s[0] == 45) { /* '-' */
112	        neg = 1;
113	        i = 1;
114	    }
115	    while (s[i] >= 48 && s[i] <= 57) { /* '0'-'9' */
116	        n = n * 10 + (s[i] - 48);
117	        i = i + 1;
118	    }
119	    if (neg) n = 0 - n;
120	    return n;
121	}
122	
123	void int_to_str(char *buf, int n) {
124	    if (n == 0) {
125	        buf[0] = 48;
126	        buf[1] = 0;
127	        return;
128	    }
129	    int neg = 0;
130	    if (n < 0) {
131	        neg = 1;
