136	    while (n > 0) {
137	        tmp[i] = 48 + n % 10;
138	        n = n / 10;
139	        i = i + 1;
140	    }
141	    int j = 0;
142	    if (neg) {
143	        buf[0] = 45;
144	        j = 1;
145	    }
146	    while (i > 0) {
147	        i = i - 1;
148	        buf[j] = tmp[i];
149	        j = j + 1;
150	    }
151	    buf[j] = 0;
152	}
153	
154	/* ---- Tokenizer ---- */
155	
156	/* Token types */
157	#define TOK_WORD   0
158	#define TOK_QUOTED 1
159	#define TOK_BLOCK  2
160	
161	/* Flat buffer: token i starts at token_starts[i] in token_pool */
162	#define TOKEN_POOL_SIZE 2048
163	char token_pool[TOKEN_POOL_SIZE];
164	int  token_starts[MAX_TOKENS];
165	int  token_type[MAX_TOKENS];
166	int  token_count;
167	int  token_pool_used;
