169	/* Get pointer to token string */
170	char *token_str(int idx) {
171	    return token_pool + token_starts[idx];
172	}
173	
174	/* Append a char to the current token being built */
175	void tok_putc(int ch) {
176	    if (token_pool_used < TOKEN_POOL_SIZE - 1) {
177	        token_pool[token_pool_used] = ch;
178	        token_pool_used = token_pool_used + 1;
179	    }
180	}
181	
182	/* Terminate the current token */
183	void tok_end() {
184	    if (token_pool_used < TOKEN_POOL_SIZE) {
185	        token_pool[token_pool_used] = 0;
186	        token_pool_used = token_pool_used + 1;
187	    }
188	}
