190	/* tokenize_line: split a line into tokens.
191	 * Returns token count, or -1 on syntax error.
192	 */
193	int tokenize_line(char *line) {
194	    int i = 0;
195	    token_count = 0;
196	    token_pool_used = 0;
197	
198	    while (line[i]) {
199	        /* skip whitespace */
200	        while (line[i] == 32 || line[i] == 9)
201	            i = i + 1;
202	
203	        if (line[i] == 0) break;
204	
205	        /* comment — rest of line ignored */
206	        if (line[i] == 35) break;
207	
208	        if (token_count >= MAX_TOKENS) break;
209	
210	        if (line[i] == 34) { /* '"' — quoted string */
211	            token_starts[token_count] = token_pool_used;
212	            i = i + 1; /* skip opening quote */
213	            while (line[i] && line[i] != 34) {
214	                if (line[i] == 92 && line[i + 1]) { /* backslash escape */
215	                    i = i + 1;
216	                    if (line[i] == 110)
217	                        tok_putc(10); /* \n */
218	                    else if (line[i] == 116)
219	                        tok_putc(9); /* \t */
220	                    else
221	                        tok_putc(line[i]);
222	                    i = i + 1;
223	                } else {
224	                    tok_putc(line[i]);
225	                    i = i + 1;
226	                }
227	            }
228	            if (line[i] != 34) {
229	                uart_puts("error: unterminated quote");
230	                uart_newline();
231	                return -1;
232	            }
233	            i = i + 1; /* skip closing quote */
234	            tok_end();
235	            token_type[token_count] = TOK_QUOTED;
236	            token_count = token_count + 1;
237	
238	        } else if (line[i] == 123) { /* '{' — brace block */
239	            token_starts[token_count] = token_pool_used;
240	            int depth = 1;
241	            tok_putc(line[i]); /* opening brace */
242	            i = i + 1;
243	            while (line[i] && depth > 0) {
244	                if (line[i] == 123) depth = depth + 1;
245	                if (line[i] == 125) depth = depth - 1;
246	                tok_putc(line[i]);
247	                i = i + 1;
248	            }
249	            if (depth != 0) {
250	                uart_puts("error: unterminated brace");
251	                uart_newline();
252	                return -1;
253	            }
254	            tok_end();
255	            token_type[token_count] = TOK_BLOCK;
256	            token_count = token_count + 1;
257	
258	        } else { /* bare word */
259	            token_starts[token_count] = token_pool_used;
260	            while (line[i] && line[i] != 32 && line[i] != 9
261	                   && line[i] != 35) {
262	                tok_putc(line[i]);
263	                i = i + 1;
264	            }
265	            tok_end();
266	            token_type[token_count] = TOK_WORD;
267	            token_count = token_count + 1;
268	        }
269	    }
270	
271	    return token_count;
272	}
273	
274	/* ---- Input buffer ---- */
275	
276	char line_buf[MAX_LINE_LEN];
277	
278	int read_line(char *buf, int max) {
279	    int i = 0;
280	    int brace_depth = 0;
281	    while (i < max - 1) {
282	        int ch = uart_getc();
283	        if (ch == 4) { /* Ctrl-D: EOF */
284	            if (i == 0) return -1;
285	            break;
286	        }
287	        if (ch == 10 || ch == 13) { /* newline */
288	            if (brace_depth <= 0) break;
289	            /* Inside braces: treat newline as newline in block */
290	            buf[i] = 10;
291	            i = i + 1;
292	            continue;
293	        }
294	        buf[i] = ch;
295	        i = i + 1;
296	        if (ch == 123) brace_depth = brace_depth + 1; /* '{' */
297	        if (ch == 125) brace_depth = brace_depth - 1; /* '}' */
298	    }
299	    buf[i] = 0;
300	    return i;
301	}
302	
303	/* ---- Halt ---- */
304	
305	void halt() {
306	    asm("_user_halt:");
307	    asm("bra _user_halt");
308	}
309	
310	/* ---- Main ---- */
311	
312	char *tok_type_name(int t) {
313	    if (t == TOK_WORD)   return "WORD";
314	    if (t == TOK_QUOTED) return "QUOTED";
315	    if (t == TOK_BLOCK)  return "BLOCK";
316	    return "?";
317	}
318	
319	int main() {
320	    uart_puts("sws 0.1");
321	    uart_newline();
322	
323	    while (1) {
324	        uart_puts("> ");
325	        int len = read_line(line_buf, MAX_LINE_LEN);
326	        if (len < 0) break; /* EOF */
327	        if (len == 0) continue; /* empty line */
328	
329	        int count = tokenize_line(line_buf);
330	        if (count < 0) continue; /* syntax error already reported */
331	        if (count == 0) continue; /* blank or comment-only */
332	
333	        /* Debug: echo tokens */
334	        int j = 0;
335	        while (j < count) {
336	            uart_puts("[");
337	            uart_puts(tok_type_name(token_type[j]));
338	            uart_puts("|");
339	            uart_puts(token_str(j));
340	            uart_puts("]");
341	            if (j < count - 1) uart_putc(32); /* space */
342	            j = j + 1;
343	        }
344	        uart_newline();
345	    }
