        if (val_rec_fields[rec_idx][i] == field_name_idx) {
            val_rec_values[rec_idx][i] = val_idx;
            return 0;
        }
        i = i + 1;
    }

    /* Add new field */
    if (fc >= MAX_FIELDS) return -1;
    val_rec_fields[rec_idx][fc] = field_name_idx;
    val_rec_values[rec_idx][fc] = val_idx;
    val_rec_count[rec_idx] = fc + 1;
    return 0;
}

