    while (line[i]) {
        /* skip whitespace */
        while (line[i] == 32 || line[i] == 9)
            i = i + 1;

        if (line[i] == 0) break;

        /* comment — rest of line ignored */
        if (line[i] == 35) break;

        if (token_count >= MAX_TOKENS) break;

        if (line[i] == 34) { /* '"' — quoted string */
            token_starts[token_count] = token_pool_used;
            i = i + 1; /* skip opening quote */
            while (line[i] && line[i] != 34) {
                if (line[i] == 92 && line[i + 1]) { /* backslash escape */
                    i = i + 1;
                    if (line[i] == 110)
                        tok_putc(10); /* \n */
                    else if (line[i] == 116)
                        tok_putc(9); /* \t */
                    else
                        tok_putc(line[i]);
                    i = i + 1;
                } else {
                    tok_putc(line[i]);
                    i = i + 1;
                }
            }
            if (line[i] != 34) {
                uart_puts("error: unterminated quote");
                uart_newline();
                return -1;
            }
            i = i + 1; /* skip closing quote */
            tok_end();
            token_type[token_count] = TOK_QUOTED;
            token_count = token_count + 1;

        } else if (line[i] == 123) { /* '{' — brace block */
            token_starts[token_count] = token_pool_used;
            int depth = 1;
            tok_putc(line[i]); /* opening brace */
            i = i + 1;
            while (line[i] && depth > 0) {
                if (line[i] == 123) depth = depth + 1;
                if (line[i] == 125) depth = depth - 1;
                tok_putc(line[i]);
                i = i + 1;
            }
            if (depth != 0) {
                uart_puts("error: unterminated brace");
                uart_newline();
                return -1;
            }
            tok_end();
            token_type[token_count] = TOK_BLOCK;
            token_count = token_count + 1;

        } else { /* bare word */
            token_starts[token_count] = token_pool_used;
            while (line[i] && line[i] != 32 && line[i] != 9
                   && line[i] != 35) {
                tok_putc(line[i]);
                i = i + 1;
            }
            tok_end();
            token_type[token_count] = TOK_WORD;
            token_count = token_count + 1;
        }
    }

    return token_count;
}

/* ---- Value type system ---- */

/* Type tags */
#define VAL_INT 0
#define VAL_STR 1
#define VAL_REC 2

/* Value storage limits */
#define MAX_VALS       64

/* Parallel arrays for value storage.
 * 2D arrays are flattened to 1D to avoid large strides that
 * exceed tc24r/as24's lc immediate range (0..127). */
int  val_type[MAX_VALS];
int  val_int[MAX_VALS];
char val_str_pool[MAX_VALS * MAX_VAR_VAL];     /* flat string pool */
int  val_rec_fld[MAX_VALS * MAX_FIELDS];       /* field name value indices */
int  val_rec_val[MAX_VALS * MAX_FIELDS];       /* field value indices */
int  val_rec_count[MAX_VALS];
int  val_count;

/* Index helpers for flat arrays */
int vsp(int idx) { return idx * MAX_VAR_VAL; }  /* val_str_pool offset */
int vrf(int idx, int f) { return idx * MAX_FIELDS + f; } /* rec field offset */

/* Reset all values (call at start or between scripts) */
void val_reset() {
    val_count = 0;
}

/* Allocate a new integer value. Returns index, or -1 on overflow. */
int val_new_int(int n) {
    if (val_count >= MAX_VALS) return -1;
    int idx = val_count;
    val_type[idx] = VAL_INT;
    val_int[idx] = n;
    val_count = val_count + 1;
    return idx;
}

/* Allocate a new string value. Returns index, or -1 on overflow. */
int val_new_str(char *s) {
    if (val_count >= MAX_VALS) return -1;
    int idx = val_count;
    val_type[idx] = VAL_STR;
    /* Copy string, truncate if needed */
    int base = vsp(idx);
    int i = 0;
    while (s[i] && i < MAX_VAR_VAL - 1) {
        val_str_pool[base + i] = s[i];
        i = i + 1;
    }
    val_str_pool[base + i] = 0;
    val_count = val_count + 1;
    return idx;
}

/* Allocate a new empty record. Returns index, or -1 on overflow. */
int val_new_rec() {
    if (val_count >= MAX_VALS) return -1;
    int idx = val_count;
    val_type[idx] = VAL_REC;
    val_rec_count[idx] = 0;
    val_count = val_count + 1;
    return idx;
}

/* Set a field in a record. field_name_idx and val_idx are value indices.
 * Returns 0 on success, -1 on error. */
int val_rec_set(int rec_idx, int field_name_idx, int val_idx) {
    if (rec_idx < 0 || rec_idx >= val_count) return -1;
    if (val_type[rec_idx] != VAL_REC) return -1;

    /* Check if field already exists — update in place */
    int fc = val_rec_count[rec_idx];
    int i = 0;
    while (i < fc) {
        if (val_rec_fld[vrf(rec_idx, i)] == field_name_idx) {
            val_rec_val[vrf(rec_idx, i)] = val_idx;
            return 0;
        }
        i = i + 1;
    }

    /* Add new field */
    if (fc >= MAX_FIELDS) return -1;
    val_rec_fld[vrf(rec_idx, fc)] = field_name_idx;
    val_rec_val[vrf(rec_idx, fc)] = val_idx;
    val_rec_count[rec_idx] = fc + 1;
    return 0;
}

/* Get a field value from a record by field name string.
 * Returns value index, or -1 if not found. */
int val_rec_get(int rec_idx, char *field_name) {
    if (rec_idx < 0 || rec_idx >= val_count) return -1;
    if (val_type[rec_idx] != VAL_REC) return -1;

    int fc = val_rec_count[rec_idx];
    int i = 0;
    while (i < fc) {
        int fn_idx = val_rec_fld[vrf(rec_idx, i)];
        if (val_type[fn_idx] == VAL_STR && str_eq(val_str_pool + vsp(fn_idx), field_name)) {
            return val_rec_val[vrf(rec_idx, i)];
        }
        i = i + 1;
    }
    return -1;
}

/* Check if a record has a field. Returns 1 if exists, 0 if not. */
int val_rec_has(int rec_idx, char *field_name) {
    return val_rec_get(rec_idx, field_name) >= 0;
}

/* Format a value as a string into buf. Returns buf. */
char *val_to_str(int idx, char *buf) {
    if (idx < 0 || idx >= val_count) {
        buf[0] = 0;
        return buf;
    }
    if (val_type[idx] == VAL_INT) {
        int_to_str(buf, val_int[idx]);
    } else if (val_type[idx] == VAL_STR) {
        str_copy(buf, val_str[idx]);
    } else if (val_type[idx] == VAL_REC) {
        /* Debug representation: {field1: val1, field2: val2} */
        int p = 0;
        buf[p] = 123; /* '{' */
        p = p + 1;
        int fc = val_rec_count[idx];
        int i = 0;
        while (i < fc && p < MAX_VAR_VAL - 10) {
            if (i > 0) {
                buf[p] = 44; /* ',' */
                p = p + 1;
                buf[p] = 32; /* ' ' */
                p = p + 1;
            }
            /* field name */
            int fn_idx = val_rec_fields[idx][i];
            char tmp[MAX_VAR_VAL];
            val_to_str(fn_idx, tmp);
            int k = 0;
            while (tmp[k] && p < MAX_VAR_VAL - 5) {
                buf[p] = tmp[k];
                p = p + 1;
                k = k + 1;
            }
            buf[p] = 58; /* ':' */
            p = p + 1;
            buf[p] = 32; /* ' ' */
            p = p + 1;
            /* field value */
            int fv_idx = val_rec_values[idx][i];
            val_to_str(fv_idx, tmp);
            k = 0;
            while (tmp[k] && p < MAX_VAR_VAL - 3) {
                buf[p] = tmp[k];
                p = p + 1;
                k = k + 1;
            }
            i = i + 1;
        }
        buf[p] = 125; /* '}' */
        p = p + 1;
        buf[p] = 0;
    } else {
        buf[0] = 0;
    }
    return buf;
}

/* Compare two values for equality. Returns 1 if equal, 0 if not. */
int val_eq(int a, int b) {
    if (a < 0 || a >= val_count || b < 0 || b >= val_count) return 0;
    if (val_type[a] != val_type[b]) return 0;
    if (val_type[a] == VAL_INT) {
        return val_int[a] == val_int[b];
    }
    if (val_type[a] == VAL_STR) {
        return str_eq(val_str[a], val_str[b]);
    }
    /* Records: equal only if same index */
    return a == b;
}

/* Truthiness: nonzero int = true, nonempty string = true,
 * record = true, invalid = false. */
int val_is_truthy(int idx) {
    if (idx < 0 || idx >= val_count) return 0;
    if (val_type[idx] == VAL_INT) {
        return val_int[idx] != 0;
    }
    if (val_type[idx] == VAL_STR) {
        return val_str[idx][0] != 0;
    }
    /* Records are always truthy */
    return 1;
}

/* ---- Input buffer ---- */

char line_buf[MAX_LINE_LEN];

int read_line(char *buf, int max) {
    int i = 0;
    int brace_depth = 0;
    while (i < max - 1) {
        int ch = uart_getc();
        if (ch == 4) { /* Ctrl-D: EOF */
            if (i == 0) return -1;
            break;
        }
        if (ch == 10 || ch == 13) { /* newline */
            if (brace_depth <= 0) break;
            /* Inside braces: treat newline as newline in block */
            buf[i] = 10;
            i = i + 1;
            continue;
        }
        buf[i] = ch;
        i = i + 1;
        if (ch == 123) brace_depth = brace_depth + 1; /* '{' */
        if (ch == 125) brace_depth = brace_depth - 1; /* '}' */
    }
    buf[i] = 0;
    return i;
}

/* ---- Halt ---- */

void halt() {
    asm("_user_halt:");
    asm("bra _user_halt");
}

/* ---- Main ---- */

char *tok_type_name(int t) {
    if (t == TOK_WORD)   return "WORD";
    if (t == TOK_QUOTED) return "QUOTED";
    if (t == TOK_BLOCK)  return "BLOCK";
    return "?";
}

char val_fmt_buf[MAX_VAR_VAL];

void val_print(int idx) {
    val_to_str(idx, val_fmt_buf);
    uart_puts(val_fmt_buf);
}

int main() {
    uart_puts("sws 0.1");
    uart_newline();

    val_reset();

    while (1) {
        uart_puts("> ");
        int len = read_line(line_buf, MAX_LINE_LEN);
        if (len < 0) break; /* EOF */
        if (len == 0) continue; /* empty line */

        int count = tokenize_line(line_buf);
        if (count < 0) continue; /* syntax error already reported */
        if (count == 0) continue; /* blank or comment-only */

        /* Built-in: _valtest — exercise value type system */
        if (str_eq(token_str(0), "_valtest")) {
            val_reset();

            /* Integer values */
            int v0 = val_new_int(42);
            int v1 = val_new_int(0);
            int v2 = val_new_int(-7);

            /* String values */
            int v3 = val_new_str("hello");
            int v4 = val_new_str("");

            /* Record with fields */
            int v5 = val_new_rec();
            int fn_status = val_new_str("status");
            int fv_status = val_new_int(0);
            int fn_output = val_new_str("output");
            int fv_output = val_new_str("ok");
            val_rec_set(v5, fn_status, fv_status);
            val_rec_set(v5, fn_output, fv_output);

            /* Print each value */
            uart_puts("int:"); val_print(v0); uart_newline();
            uart_puts("zero:"); val_print(v1); uart_newline();
            uart_puts("neg:"); val_print(v2); uart_newline();
            uart_puts("str:"); val_print(v3); uart_newline();
            uart_puts("empty:"); val_print(v4); uart_newline();
            uart_puts("rec:"); val_print(v5); uart_newline();

            /* Equality tests */
            int v6 = val_new_int(42);
            uart_puts("eq:"); uart_putint(val_eq(v0, v6)); uart_newline();
            uart_puts("ne:"); uart_putint(val_eq(v0, v1)); uart_newline();

            /* Truthiness */
            uart_puts("truthy42:"); uart_putint(val_is_truthy(v0)); uart_newline();
            uart_puts("truthy0:"); uart_putint(val_is_truthy(v1)); uart_newline();
            uart_puts("truthyS:"); uart_putint(val_is_truthy(v3)); uart_newline();
            uart_puts("truthyE:"); uart_putint(val_is_truthy(v4)); uart_newline();
            uart_puts("truthyR:"); uart_putint(val_is_truthy(v5)); uart_newline();

            /* Record field access */
            int got = val_rec_get(v5, "status");
            uart_puts("field:"); val_print(got); uart_newline();
            uart_puts("has:"); uart_putint(val_rec_has(v5, "output")); uart_newline();
            uart_puts("miss:"); uart_putint(val_rec_has(v5, "nope")); uart_newline();

            uart_puts("vals:"); uart_putint(val_count); uart_newline();
            continue;
        }

        /* Debug: echo tokens */
        int j = 0;
        while (j < count) {
            uart_puts("[");
            uart_puts(tok_type_name(token_type[j]));
            uart_puts("|");
            uart_puts(token_str(j));
            uart_puts("]");
            if (j < count - 1) uart_putc(32); /* space */
            j = j + 1;
        }
        uart_newline();
    }

    halt();
    return 0;
}

/* sws.c -- Software Wrighter Script interpreter for COR24
 *
 * A Tcl-like command language for shell and editor scripting.
 * Compiled by tc24r (cross C compiler), runs on COR24 hardware or emulator.
 *
 * tc24r constraints: no structs, no malloc/free, no string library,
 * no varargs/printf, single translation unit, 24-bit int, 8-bit char.
 */

/* ---- UART I/O (memory-mapped) ---- */

#define UART_DATA   0xFF0100
#define UART_STATUS 0xFF0101

void uart_putc(int ch) {
    int tries = 50000;
    while ((*(char *)UART_STATUS & 0x80) && tries > 0) {
        tries = tries - 1;
    }
    *(char *)UART_DATA = ch;
}

int uart_getc() {
    while (!(*(char *)UART_STATUS & 0x01)) {}
    return *(char *)UART_DATA;
}

void uart_puts(char *s) {
    while (*s) {
        uart_putc(*s);
        s = s + 1;
    }
}

void uart_putint(int n) {
    if (n < 0) {
        uart_putc(45); /* '-' */
        n = 0 - n;
    }
    if (n == 0) {
        uart_putc(48); /* '0' */
        return;
    }
    char buf[12];
    int i = 0;
    while (n > 0) {
        buf[i] = 48 + n % 10;
        n = n / 10;
        i = i + 1;
    }
    while (i > 0) {
        i = i - 1;
        uart_putc(buf[i]);
    }
}

void uart_newline() {
    uart_putc(10);
}

/* ---- Static allocation limits ---- */

#define MAX_LINE_LEN   512
#define MAX_TOKENS       32
#define MAX_TOKEN_LEN   128
#define MAX_VARS         64
#define MAX_VAR_NAME     32
#define MAX_VAR_VAL     128
#define MAX_NEST         64
#define MAX_FIELDS       16

/* ---- String helpers ---- */

int str_len(char *s) {
    int n = 0;
    while (s[n]) n = n + 1;
    return n;
}

int str_eq(char *a, char *b) {
    int i = 0;
    while (a[i] && b[i]) {
        if (a[i] != b[i]) return 0;
        i = i + 1;
    }
    return a[i] == b[i];
}

void str_copy(char *dst, char *src) {
    int i = 0;
    while (src[i]) {
        dst[i] = src[i];
        i = i + 1;
    }
    dst[i] = 0;
}

int str_starts_with(char *s, char *prefix) {
    int i = 0;
    while (prefix[i]) {
        if (s[i] != prefix[i]) return 0;
        i = i + 1;
    }
    return 1;
}

int str_to_int(char *s) {
    int n = 0;
    int neg = 0;
    int i = 0;
    if (s[0] == 45) { /* '-' */
        neg = 1;
        i = 1;
    }
    while (s[i] >= 48 && s[i] <= 57) { /* '0'-'9' */
        n = n * 10 + (s[i] - 48);
        i = i + 1;
    }
    if (neg) n = 0 - n;
    return n;
}

void int_to_str(char *buf, int n) {
    if (n == 0) {
        buf[0] = 48;
        buf[1] = 0;
        return;
    }
    int neg = 0;
    if (n < 0) {
        neg = 1;
        n = 0 - n;
    }
    char tmp[12];
    int i = 0;
    while (n > 0) {
        tmp[i] = 48 + n % 10;
        n = n / 10;
        i = i + 1;
    }
    int j = 0;
    if (neg) {
        buf[0] = 45;
        j = 1;
    }
    while (i > 0) {
        i = i - 1;
        buf[j] = tmp[i];
        j = j + 1;
    }
    buf[j] = 0;
}

/* ---- Tokenizer ---- */

/* Token types */
#define TOK_WORD   0
#define TOK_QUOTED 1
#define TOK_BLOCK  2

/* Flat buffer: token i starts at token_starts[i] in token_pool */
#define TOKEN_POOL_SIZE 2048
char token_pool[TOKEN_POOL_SIZE];
int  token_starts[MAX_TOKENS];
int  token_type[MAX_TOKENS];
int  token_count;
int  token_pool_used;

/* Get pointer to token string */
char *token_str(int idx) {
    return token_pool + token_starts[idx];
}

/* Append a char to the current token being built */
void tok_putc(int ch) {
    if (token_pool_used < TOKEN_POOL_SIZE - 1) {
        token_pool[token_pool_used] = ch;
        token_pool_used = token_pool_used + 1;
    }
}

/* Terminate the current token */
void tok_end() {
    if (token_pool_used < TOKEN_POOL_SIZE) {
        token_pool[token_pool_used] = 0;
        token_pool_used = token_pool_used + 1;
    }
}

/* tokenize_line: split a line into tokens.
 * Returns token count, or -1 on syntax error.
 */
int tokenize_line(char *line) {
    int i = 0;
    token_count = 0;
    token_pool_used = 0;

    while (line[i]) {
        /* skip whitespace */
        while (line[i] == 32 || line[i] == 9)
            i = i + 1;

        if (line[i] == 0) break;

        /* comment — rest of line ignored */
        if (line[i] == 35) break;

        if (token_count >= MAX_TOKENS) break;

        if (line[i] == 34) { /* '"' — quoted string */
            token_starts[token_count] = token_pool_used;
            i = i + 1; /* skip opening quote */
            while (line[i] && line[i] != 34) {
                if (line[i] == 92 && line[i + 1]) { /* backslash escape */
                    i = i + 1;
                    if (line[i] == 110)
                        tok_putc(10); /* \n */
                    else if (line[i] == 116)
                        tok_putc(9); /* \t */
                    else
                        tok_putc(line[i]);
                    i = i + 1;
                } else {
                    tok_putc(line[i]);
                    i = i + 1;
                }
            }
            if (line[i] != 34) {
                uart_puts("error: unterminated quote");
                uart_newline();
                return -1;
            }
            i = i + 1; /* skip closing quote */
            tok_end();
            token_type[token_count] = TOK_QUOTED;
            token_count = token_count + 1;

        } else if (line[i] == 123) { /* '{' — brace block */
            token_starts[token_count] = token_pool_used;
            int depth = 1;
            tok_putc(line[i]); /* opening brace */
            i = i + 1;
            while (line[i] && depth > 0) {
                if (line[i] == 123) depth = depth + 1;
                if (line[i] == 125) depth = depth - 1;
                tok_putc(line[i]);
                i = i + 1;
            }
            if (depth != 0) {
                uart_puts("error: unterminated brace");
                uart_newline();
                return -1;
            }
            tok_end();
            token_type[token_count] = TOK_BLOCK;
            token_count = token_count + 1;

        } else { /* bare word */
            token_starts[token_count] = token_pool_used;
            while (line[i] && line[i] != 32 && line[i] != 9
                   && line[i] != 35) {
                tok_putc(line[i]);
                i = i + 1;
            }
            tok_end();
            token_type[token_count] = TOK_WORD;
            token_count = token_count + 1;
        }
    }

    return token_count;
}

/* ---- Value type system ---- */

/* Type tags */
#define VAL_INT 0
#define VAL_STR 1
#define VAL_REC 2

/* Value storage limits */
#define MAX_VALS       64

/* Parallel arrays for value storage.
 * 2D arrays are flattened to 1D to avoid large strides that
 * exceed tc24r/as24's lc immediate range (0..127). */
int  val_type[MAX_VALS];
int  val_int[MAX_VALS];
char val_str_pool[MAX_VALS * MAX_VAR_VAL];     /* flat string pool */
int  val_rec_fld[MAX_VALS * MAX_FIELDS];       /* field name value indices */
int  val_rec_val[MAX_VALS * MAX_FIELDS];       /* field value indices */
int  val_rec_count[MAX_VALS];
int  val_count;

/* Index helpers for flat arrays */
int vsp(int idx) { return idx * MAX_VAR_VAL; }  /* val_str_pool offset */
int vrf(int idx, int f) { return idx * MAX_FIELDS + f; } /* rec field offset */

/* Reset all values (call at start or between scripts) */
void val_reset() {
    val_count = 0;
}

/* Allocate a new integer value. Returns index, or -1 on overflow. */
int val_new_int(int n) {
    if (val_count >= MAX_VALS) return -1;
    int idx = val_count;
    val_type[idx] = VAL_INT;
    val_int[idx] = n;
    val_count = val_count + 1;
    return idx;
}

/* Allocate a new string value. Returns index, or -1 on overflow. */
int val_new_str(char *s) {
    if (val_count >= MAX_VALS) return -1;
    int idx = val_count;
    val_type[idx] = VAL_STR;
    /* Copy string, truncate if needed */
    int base = vsp(idx);
    int i = 0;
    while (s[i] && i < MAX_VAR_VAL - 1) {
        val_str_pool[base + i] = s[i];
        i = i + 1;
    }
    val_str_pool[base + i] = 0;
    val_count = val_count + 1;
    return idx;
}

/* Allocate a new empty record. Returns index, or -1 on overflow. */
int val_new_rec() {
    if (val_count >= MAX_VALS) return -1;
    int idx = val_count;
    val_type[idx] = VAL_REC;
    val_rec_count[idx] = 0;
    val_count = val_count + 1;
    return idx;
}

/* Set a field in a record. field_name_idx and val_idx are value indices.
 * Returns 0 on success, -1 on error. */
int val_rec_set(int rec_idx, int field_name_idx, int val_idx) {
    if (rec_idx < 0 || rec_idx >= val_count) return -1;
    if (val_type[rec_idx] != VAL_REC) return -1;

    /* Check if field already exists — update in place */
    int fc = val_rec_count[rec_idx];
    int i = 0;
    while (i < fc) {
        if (val_rec_fld[vrf(rec_idx, i)] == field_name_idx) {
            val_rec_val[vrf(rec_idx, i)] = val_idx;
            return 0;
        }
        i = i + 1;
    }

    /* Add new field */
    if (fc >= MAX_FIELDS) return -1;
    val_rec_fld[vrf(rec_idx, fc)] = field_name_idx;
    val_rec_val[vrf(rec_idx, fc)] = val_idx;
    val_rec_count[rec_idx] = fc + 1;
    return 0;
}

/* Get a field value from a record by field name string.
 * Returns value index, or -1 if not found. */
int val_rec_get(int rec_idx, char *field_name) {
    if (rec_idx < 0 || rec_idx >= val_count) return -1;
    if (val_type[rec_idx] != VAL_REC) return -1;

    int fc = val_rec_count[rec_idx];
    int i = 0;
    while (i < fc) {
        int fn_idx = val_rec_fld[vrf(rec_idx, i)];
        if (val_type[fn_idx] == VAL_STR && str_eq(val_str_pool + vsp(fn_idx), field_name)) {
            return val_rec_val[vrf(rec_idx, i)];
        }
        i = i + 1;
    }
    return -1;
}

/* Check if a record has a field. Returns 1 if exists, 0 if not. */
int val_rec_has(int rec_idx, char *field_name) {
    return val_rec_get(rec_idx, field_name) >= 0;
}

/* Format a value as a string into buf. Returns buf. */
char *val_to_str(int idx, char *buf) {
    if (idx < 0 || idx >= val_count) {
        buf[0] = 0;
        return buf;
    }
    if (val_type[idx] == VAL_INT) {
        int_to_str(buf, val_int[idx]);
    } else if (val_type[idx] == VAL_STR) {
        str_copy(buf, val_str_pool + vsp(idx));
    } else if (val_type[idx] == VAL_REC) {
        /* Debug representation: {field1: val1, field2: val2} */
        int p = 0;
        buf[p] = 123; /* '{' */
        p = p + 1;
        int fc = val_rec_count[idx];
        int i = 0;
        while (i < fc && p < MAX_VAR_VAL - 10) {
            if (i > 0) {
                buf[p] = 44; /* ',' */
                p = p + 1;
                buf[p] = 32; /* ' ' */
                p = p + 1;
            }
            /* field name */
            int fn_idx = val_rec_fields[idx][i];
            char tmp[MAX_VAR_VAL];
            val_to_str(fn_idx, tmp);
            int k = 0;
            while (tmp[k] && p < MAX_VAR_VAL - 5) {
                buf[p] = tmp[k];
                p = p + 1;
                k = k + 1;
            }
            buf[p] = 58; /* ':' */
            p = p + 1;
            buf[p] = 32; /* ' ' */
            p = p + 1;
            /* field value */
            int fv_idx = val_rec_values[idx][i];
            val_to_str(fv_idx, tmp);
            k = 0;
            while (tmp[k] && p < MAX_VAR_VAL - 3) {
                buf[p] = tmp[k];
                p = p + 1;
                k = k + 1;
            }
            i = i + 1;
        }
        buf[p] = 125; /* '}' */
        p = p + 1;
        buf[p] = 0;
    } else {
        buf[0] = 0;
    }
    return buf;
}

/* Compare two values for equality. Returns 1 if equal, 0 if not. */
int val_eq(int a, int b) {
    if (a < 0 || a >= val_count || b < 0 || b >= val_count) return 0;
    if (val_type[a] != val_type[b]) return 0;
    if (val_type[a] == VAL_INT) {
        return val_int[a] == val_int[b];
    }
    if (val_type[a] == VAL_STR) {
        return str_eq(val_str[a], val_str[b]);
    }
    /* Records: equal only if same index */
    return a == b;
}

/* Truthiness: nonzero int = true, nonempty string = true,
 * record = true, invalid = false. */
int val_is_truthy(int idx) {
    if (idx < 0 || idx >= val_count) return 0;
    if (val_type[idx] == VAL_INT) {
        return val_int[idx] != 0;
    }
    if (val_type[idx] == VAL_STR) {
        return val_str[idx][0] != 0;
    }
    /* Records are always truthy */
    return 1;
}

/* ---- Input buffer ---- */

char line_buf[MAX_LINE_LEN];

int read_line(char *buf, int max) {
    int i = 0;
    int brace_depth = 0;
    while (i < max - 1) {
        int ch = uart_getc();
        if (ch == 4) { /* Ctrl-D: EOF */
            if (i == 0) return -1;
            break;
        }
        if (ch == 10 || ch == 13) { /* newline */
            if (brace_depth <= 0) break;
            /* Inside braces: treat newline as newline in block */
            buf[i] = 10;
            i = i + 1;
            continue;
        }
        buf[i] = ch;
        i = i + 1;
        if (ch == 123) brace_depth = brace_depth + 1; /* '{' */
        if (ch == 125) brace_depth = brace_depth - 1; /* '}' */
    }
    buf[i] = 0;
    return i;
}

/* ---- Halt ---- */

void halt() {
    asm("_user_halt:");
    asm("bra _user_halt");
}

/* ---- Main ---- */

char *tok_type_name(int t) {
    if (t == TOK_WORD)   return "WORD";
    if (t == TOK_QUOTED) return "QUOTED";
    if (t == TOK_BLOCK)  return "BLOCK";
    return "?";
}

char val_fmt_buf[MAX_VAR_VAL];

void val_print(int idx) {
    val_to_str(idx, val_fmt_buf);
    uart_puts(val_fmt_buf);
}

int main() {
    uart_puts("sws 0.1");
    uart_newline();

    val_reset();

    while (1) {
        uart_puts("> ");
        int len = read_line(line_buf, MAX_LINE_LEN);
        if (len < 0) break; /* EOF */
        if (len == 0) continue; /* empty line */

        int count = tokenize_line(line_buf);
        if (count < 0) continue; /* syntax error already reported */
        if (count == 0) continue; /* blank or comment-only */

        /* Built-in: _valtest — exercise value type system */
        if (str_eq(token_str(0), "_valtest")) {
            val_reset();

            /* Integer values */
            int v0 = val_new_int(42);
            int v1 = val_new_int(0);
            int v2 = val_new_int(-7);

            /* String values */
            int v3 = val_new_str("hello");
            int v4 = val_new_str("");

            /* Record with fields */
            int v5 = val_new_rec();
            int fn_status = val_new_str("status");
            int fv_status = val_new_int(0);
            int fn_output = val_new_str("output");
            int fv_output = val_new_str("ok");
            val_rec_set(v5, fn_status, fv_status);
            val_rec_set(v5, fn_output, fv_output);

            /* Print each value */
            uart_puts("int:"); val_print(v0); uart_newline();
            uart_puts("zero:"); val_print(v1); uart_newline();
            uart_puts("neg:"); val_print(v2); uart_newline();
            uart_puts("str:"); val_print(v3); uart_newline();
            uart_puts("empty:"); val_print(v4); uart_newline();
            uart_puts("rec:"); val_print(v5); uart_newline();

            /* Equality tests */
            int v6 = val_new_int(42);
            uart_puts("eq:"); uart_putint(val_eq(v0, v6)); uart_newline();
            uart_puts("ne:"); uart_putint(val_eq(v0, v1)); uart_newline();

            /* Truthiness */
            uart_puts("truthy42:"); uart_putint(val_is_truthy(v0)); uart_newline();
            uart_puts("truthy0:"); uart_putint(val_is_truthy(v1)); uart_newline();
            uart_puts("truthyS:"); uart_putint(val_is_truthy(v3)); uart_newline();
            uart_puts("truthyE:"); uart_putint(val_is_truthy(v4)); uart_newline();
            uart_puts("truthyR:"); uart_putint(val_is_truthy(v5)); uart_newline();

            /* Record field access */
            int got = val_rec_get(v5, "status");
            uart_puts("field:"); val_print(got); uart_newline();
            uart_puts("has:"); uart_putint(val_rec_has(v5, "output")); uart_newline();
            uart_puts("miss:"); uart_putint(val_rec_has(v5, "nope")); uart_newline();

            uart_puts("vals:"); uart_putint(val_count); uart_newline();
            continue;
        }

        /* Debug: echo tokens */
        int j = 0;
        while (j < count) {
            uart_puts("[");
            uart_puts(tok_type_name(token_type[j]));
            uart_puts("|");
            uart_puts(token_str(j));
            uart_puts("]");
            if (j < count - 1) uart_putc(32); /* space */
            j = j + 1;
        }
        uart_newline();
    }

    halt();
    return 0;
}

/* sws.c -- Software Wrighter Script interpreter for COR24
 *
 * A Tcl-like command language for shell and editor scripting.
 * Compiled by tc24r (cross C compiler), runs on COR24 hardware or emulator.
 *
 * tc24r constraints: no structs, no malloc/free, no string library,
 * no varargs/printf, single translation unit, 24-bit int, 8-bit char.
 */

/* ---- UART I/O (memory-mapped) ---- */

#define UART_DATA   0xFF0100
#define UART_STATUS 0xFF0101

void uart_putc(int ch) {
    int tries = 50000;
    while ((*(char *)UART_STATUS & 0x80) && tries > 0) {
        tries = tries - 1;
    }
    *(char *)UART_DATA = ch;
}

int uart_getc() {
    while (!(*(char *)UART_STATUS & 0x01)) {}
    return *(char *)UART_DATA;
}

void uart_puts(char *s) {
    while (*s) {
        uart_putc(*s);
        s = s + 1;
    }
}

void uart_putint(int n) {
    if (n < 0) {
        uart_putc(45); /* '-' */
        n = 0 - n;
    }
    if (n == 0) {
        uart_putc(48); /* '0' */
        return;
    }
    char buf[12];
    int i = 0;
    while (n > 0) {
        buf[i] = 48 + n % 10;
        n = n / 10;
        i = i + 1;
    }
    while (i > 0) {
        i = i - 1;
        uart_putc(buf[i]);
    }
}

void uart_newline() {
    uart_putc(10);
}

/* ---- Static allocation limits ---- */

#define MAX_LINE_LEN   512
#define MAX_TOKENS       32
#define MAX_TOKEN_LEN   128
#define MAX_VARS         64
#define MAX_VAR_NAME     32
#define MAX_VAR_VAL     128
#define MAX_NEST         64
#define MAX_FIELDS       16

/* ---- String helpers ---- */

int str_len(char *s) {
    int n = 0;
    while (s[n]) n = n + 1;
    return n;
}

int str_eq(char *a, char *b) {
    int i = 0;
    while (a[i] && b[i]) {
        if (a[i] != b[i]) return 0;
        i = i + 1;
    }
    return a[i] == b[i];
}

void str_copy(char *dst, char *src) {
    int i = 0;
    while (src[i]) {
        dst[i] = src[i];
        i = i + 1;
    }
    dst[i] = 0;
}

int str_starts_with(char *s, char *prefix) {
    int i = 0;
    while (prefix[i]) {
        if (s[i] != prefix[i]) return 0;
        i = i + 1;
    }
    return 1;
}

int str_to_int(char *s) {
    int n = 0;
    int neg = 0;
    int i = 0;
    if (s[0] == 45) { /* '-' */
        neg = 1;
        i = 1;
    }
    while (s[i] >= 48 && s[i] <= 57) { /* '0'-'9' */
        n = n * 10 + (s[i] - 48);
        i = i + 1;
    }
    if (neg) n = 0 - n;
    return n;
}

void int_to_str(char *buf, int n) {
    if (n == 0) {
        buf[0] = 48;
        buf[1] = 0;
        return;
    }
    int neg = 0;
    if (n < 0) {
        neg = 1;
        n = 0 - n;
    }
    char tmp[12];
    int i = 0;
    while (n > 0) {
        tmp[i] = 48 + n % 10;
        n = n / 10;
        i = i + 1;
    }
    int j = 0;
    if (neg) {
        buf[0] = 45;
        j = 1;
    }
    while (i > 0) {
        i = i - 1;
        buf[j] = tmp[i];
        j = j + 1;
    }
    buf[j] = 0;
}

/* ---- Tokenizer ---- */

/* Token types */
#define TOK_WORD   0
#define TOK_QUOTED 1
#define TOK_BLOCK  2

/* Flat buffer: token i starts at token_starts[i] in token_pool */
#define TOKEN_POOL_SIZE 2048
char token_pool[TOKEN_POOL_SIZE];
int  token_starts[MAX_TOKENS];
int  token_type[MAX_TOKENS];
int  token_count;
int  token_pool_used;

/* Get pointer to token string */
char *token_str(int idx) {
    return token_pool + token_starts[idx];
}

/* Append a char to the current token being built */
void tok_putc(int ch) {
    if (token_pool_used < TOKEN_POOL_SIZE - 1) {
        token_pool[token_pool_used] = ch;
        token_pool_used = token_pool_used + 1;
    }
}

/* Terminate the current token */
void tok_end() {
    if (token_pool_used < TOKEN_POOL_SIZE) {
        token_pool[token_pool_used] = 0;
        token_pool_used = token_pool_used + 1;
    }
}

/* tokenize_line: split a line into tokens.
 * Returns token count, or -1 on syntax error.
 */
int tokenize_line(char *line) {
    int i = 0;
    token_count = 0;
    token_pool_used = 0;

    while (line[i]) {
        /* skip whitespace */
        while (line[i] == 32 || line[i] == 9)
            i = i + 1;

        if (line[i] == 0) break;

        /* comment — rest of line ignored */
        if (line[i] == 35) break;

        if (token_count >= MAX_TOKENS) break;

        if (line[i] == 34) { /* '"' — quoted string */
            token_starts[token_count] = token_pool_used;
            i = i + 1; /* skip opening quote */
            while (line[i] && line[i] != 34) {
                if (line[i] == 92 && line[i + 1]) { /* backslash escape */
                    i = i + 1;
                    if (line[i] == 110)
                        tok_putc(10); /* \n */
                    else if (line[i] == 116)
                        tok_putc(9); /* \t */
                    else
                        tok_putc(line[i]);
                    i = i + 1;
                } else {
                    tok_putc(line[i]);
                    i = i + 1;
                }
            }
            if (line[i] != 34) {
                uart_puts("error: unterminated quote");
                uart_newline();
                return -1;
            }
            i = i + 1; /* skip closing quote */
            tok_end();
            token_type[token_count] = TOK_QUOTED;
            token_count = token_count + 1;

        } else if (line[i] == 123) { /* '{' — brace block */
            token_starts[token_count] = token_pool_used;
            int depth = 1;
            tok_putc(line[i]); /* opening brace */
            i = i + 1;
            while (line[i] && depth > 0) {
                if (line[i] == 123) depth = depth + 1;
                if (line[i] == 125) depth = depth - 1;
                tok_putc(line[i]);
                i = i + 1;
            }
            if (depth != 0) {
                uart_puts("error: unterminated brace");
                uart_newline();
                return -1;
            }
            tok_end();
            token_type[token_count] = TOK_BLOCK;
            token_count = token_count + 1;

        } else { /* bare word */
            token_starts[token_count] = token_pool_used;
            while (line[i] && line[i] != 32 && line[i] != 9
                   && line[i] != 35) {
                tok_putc(line[i]);
                i = i + 1;
            }
            tok_end();
            token_type[token_count] = TOK_WORD;
            token_count = token_count + 1;
        }
    }

    return token_count;
}

/* ---- Value type system ---- */

/* Type tags */
#define VAL_INT 0
#define VAL_STR 1
#define VAL_REC 2

/* Value storage limits */
#define MAX_VALS       64

/* Parallel arrays for value storage.
 * 2D arrays are flattened to 1D to avoid large strides that
 * exceed tc24r/as24's lc immediate range (0..127). */
int  val_type[MAX_VALS];
int  val_int[MAX_VALS];
char val_str_pool[MAX_VALS * MAX_VAR_VAL];     /* flat string pool */
int  val_rec_fld[MAX_VALS * MAX_FIELDS];       /* field name value indices */
int  val_rec_val[MAX_VALS * MAX_FIELDS];       /* field value indices */
int  val_rec_count[MAX_VALS];
int  val_count;

/* Index helpers for flat arrays */
int vsp(int idx) { return idx * MAX_VAR_VAL; }  /* val_str_pool offset */
int vrf(int idx, int f) { return idx * MAX_FIELDS + f; } /* rec field offset */

/* Reset all values (call at start or between scripts) */
void val_reset() {
    val_count = 0;
}

/* Allocate a new integer value. Returns index, or -1 on overflow. */
int val_new_int(int n) {
    if (val_count >= MAX_VALS) return -1;
    int idx = val_count;
    val_type[idx] = VAL_INT;
    val_int[idx] = n;
    val_count = val_count + 1;
    return idx;
}

/* Allocate a new string value. Returns index, or -1 on overflow. */
int val_new_str(char *s) {
    if (val_count >= MAX_VALS) return -1;
    int idx = val_count;
    val_type[idx] = VAL_STR;
    /* Copy string, truncate if needed */
    int base = vsp(idx);
    int i = 0;
    while (s[i] && i < MAX_VAR_VAL - 1) {
        val_str_pool[base + i] = s[i];
        i = i + 1;
    }
    val_str_pool[base + i] = 0;
    val_count = val_count + 1;
    return idx;
}

/* Allocate a new empty record. Returns index, or -1 on overflow. */
int val_new_rec() {
    if (val_count >= MAX_VALS) return -1;
    int idx = val_count;
    val_type[idx] = VAL_REC;
    val_rec_count[idx] = 0;
    val_count = val_count + 1;
    return idx;
}

/* Set a field in a record. field_name_idx and val_idx are value indices.
 * Returns 0 on success, -1 on error. */
int val_rec_set(int rec_idx, int field_name_idx, int val_idx) {
    if (rec_idx < 0 || rec_idx >= val_count) return -1;
    if (val_type[rec_idx] != VAL_REC) return -1;

    /* Check if field already exists — update in place */
    int fc = val_rec_count[rec_idx];
    int i = 0;
    while (i < fc) {
        if (val_rec_fld[vrf(rec_idx, i)] == field_name_idx) {
            val_rec_val[vrf(rec_idx, i)] = val_idx;
            return 0;
        }
        i = i + 1;
    }

    /* Add new field */
    if (fc >= MAX_FIELDS) return -1;
    val_rec_fld[vrf(rec_idx, fc)] = field_name_idx;
    val_rec_val[vrf(rec_idx, fc)] = val_idx;
    val_rec_count[rec_idx] = fc + 1;
    return 0;
}

/* Get a field value from a record by field name string.
 * Returns value index, or -1 if not found. */
int val_rec_get(int rec_idx, char *field_name) {
    if (rec_idx < 0 || rec_idx >= val_count) return -1;
    if (val_type[rec_idx] != VAL_REC) return -1;

    int fc = val_rec_count[rec_idx];
    int i = 0;
    while (i < fc) {
        int fn_idx = val_rec_fld[vrf(rec_idx, i)];
        if (val_type[fn_idx] == VAL_STR && str_eq(val_str_pool + vsp(fn_idx), field_name)) {
            return val_rec_val[vrf(rec_idx, i)];
        }
        i = i + 1;
    }
    return -1;
}

/* Check if a record has a field. Returns 1 if exists, 0 if not. */
int val_rec_has(int rec_idx, char *field_name) {
    return val_rec_get(rec_idx, field_name) >= 0;
}

/* Format a value as a string into buf. Returns buf. */
char *val_to_str(int idx, char *buf) {
    if (idx < 0 || idx >= val_count) {
        buf[0] = 0;
        return buf;
    }
    if (val_type[idx] == VAL_INT) {
        int_to_str(buf, val_int[idx]);
    } else if (val_type[idx] == VAL_STR) {
        str_copy(buf, val_str_pool + vsp(idx));
    } else if (val_type[idx] == VAL_REC) {
        /* Debug representation: {field1: val1, field2: val2} */
        int p = 0;
        buf[p] = 123; /* '{' */
        p = p + 1;
        int fc = val_rec_count[idx];
        int i = 0;
        while (i < fc && p < MAX_VAR_VAL - 10) {
            if (i > 0) {
                buf[p] = 44; /* ',' */
                p = p + 1;
                buf[p] = 32; /* ' ' */
                p = p + 1;
            }
            /* field name */
            int fn_idx = val_rec_fld[vrf(idx, i)];
            char tmp[MAX_VAR_VAL];
            val_to_str(fn_idx, tmp);
            int k = 0;
            while (tmp[k] && p < MAX_VAR_VAL - 5) {
                buf[p] = tmp[k];
                p = p + 1;
                k = k + 1;
            }
            buf[p] = 58; /* ':' */
            p = p + 1;
            buf[p] = 32; /* ' ' */
            p = p + 1;
            /* field value */
            int fv_idx = val_rec_values[idx][i];
            val_to_str(fv_idx, tmp);
            k = 0;
            while (tmp[k] && p < MAX_VAR_VAL - 3) {
                buf[p] = tmp[k];
                p = p + 1;
                k = k + 1;
            }
            i = i + 1;
        }
        buf[p] = 125; /* '}' */
        p = p + 1;
        buf[p] = 0;
    } else {
        buf[0] = 0;
    }
    return buf;
}

/* Compare two values for equality. Returns 1 if equal, 0 if not. */
int val_eq(int a, int b) {
    if (a < 0 || a >= val_count || b < 0 || b >= val_count) return 0;
    if (val_type[a] != val_type[b]) return 0;
    if (val_type[a] == VAL_INT) {
        return val_int[a] == val_int[b];
    }
    if (val_type[a] == VAL_STR) {
        return str_eq(val_str[a], val_str[b]);
    }
    /* Records: equal only if same index */
    return a == b;
}

/* Truthiness: nonzero int = true, nonempty string = true,
 * record = true, invalid = false. */
int val_is_truthy(int idx) {
    if (idx < 0 || idx >= val_count) return 0;
    if (val_type[idx] == VAL_INT) {
        return val_int[idx] != 0;
    }
    if (val_type[idx] == VAL_STR) {
        return val_str[idx][0] != 0;
    }
    /* Records are always truthy */
    return 1;
}

/* ---- Input buffer ---- */

char line_buf[MAX_LINE_LEN];

int read_line(char *buf, int max) {
    int i = 0;
    int brace_depth = 0;
    while (i < max - 1) {
        int ch = uart_getc();
        if (ch == 4) { /* Ctrl-D: EOF */
            if (i == 0) return -1;
            break;
        }
        if (ch == 10 || ch == 13) { /* newline */
            if (brace_depth <= 0) break;
            /* Inside braces: treat newline as newline in block */
            buf[i] = 10;
            i = i + 1;
            continue;
        }
        buf[i] = ch;
        i = i + 1;
        if (ch == 123) brace_depth = brace_depth + 1; /* '{' */
        if (ch == 125) brace_depth = brace_depth - 1; /* '}' */
    }
    buf[i] = 0;
    return i;
}

/* ---- Halt ---- */

void halt() {
    asm("_user_halt:");
    asm("bra _user_halt");
}

/* ---- Main ---- */

char *tok_type_name(int t) {
